void startReceive ( dword socket, char buffer[] )
{
  long result;
  result = TcpReceive( socket, buffer, elcount(buffer) );
  if (result == -1)
  {
    result = IpGetLastSocketError(socket);
    if (result != 997)
    {
      // failure
      writeLineEx( 1, 3, “TcpReceive error %d”, result);
    }
  }
  else
  {
    // failure
    writeLIneEx( 1, 3, “TcpReceive error %d”, result);
  }
}
